class Solution:
    def canIWin(self, maxChoosableInteger: int, desiredTotal: int) -> bool:
        if (maxChoosableInteger * (maxChoosableInteger + 1)) // 2 < desiredTotal:
            return False
        self.memo = {}
        return self.dfs(tuple(range(1, maxChoosableInteger + 1)), desiredTotal)

    def dfs(self, nums, target):
        if nums[-1] >= target:
            return True
        if (nums, target) in self.memo:
            return self.memo[(nums, target)]
        for i in range(len(nums)):
            if not self.dfs(nums[:i] + nums[i + 1:], target - nums[i]):
                self.memo[(nums, target)] = True
                return True
        self.memo[(nums, target)] = False
        return False
```
